import{DEFAULT_CONFIG,AVAILABLE_MODULES}from"./fwku-config.js";const LOG_STYLES={log:"color: #0d6efd; font-weight: bold;",warn:"color: #ffc107; font-weight: bold;",error:"color: #dc3545; font-weight: bold;"};export function log(t,o="log",e=!1){if(!e)return;const r=console[o];"function"==typeof r&&r("%c[FWK Utilities]",LOG_STYLES[o],t)}export function validateModules(t){if(!Array.isArray(t))return{valid:[],invalid:[]};const o=[],e=[];for(const r of t){const t=String(r).toLowerCase().trim();AVAILABLE_MODULES.includes(t)?o.push(t):e.push(String(r))}return{valid:o,invalid:e}}export function getConfigFromHTML(){const t={...DEFAULT_CONFIG},o=document.body?.dataset?.fwkuModules;if(o)return t.modules=o.split(",").map(t=>t.trim()),t;const e=document.querySelector('meta[name="fwk-utilities"]');if(e){const o=(e.getAttribute("content")??"").match(/modules:([^;]+)/);if(o)return t.modules=o[1].split(",").map(t=>t.trim()),t}const r=document.getElementById("fwku-config");if(r instanceof HTMLScriptElement&&"application/json"===r.type)try{const o=JSON.parse(r.textContent??"{}");return{...t,...o}}catch(t){log(`Erro ao parsear configuração JSON: ${t instanceof Error?t.message:String(t)}`,"error",!0)}return t}export function mergeConfig(t={}){return{...DEFAULT_CONFIG,...t,accessibility:{...DEFAULT_CONFIG.accessibility,...t.accessibility??{}},datepicker:{...DEFAULT_CONFIG.datepicker,...t.datepicker??{}},export:{...DEFAULT_CONFIG.export,...t.export??{}}}}export default{log:log,validateModules:validateModules,getConfigFromHTML:getConfigFromHTML,mergeConfig:mergeConfig};